pub fn allows_initial_turn_overrides(
    current_phase: DeferredTurnFirstTurnPhase,
) -> Result<bool, SessionDeferredTurnAuthorityError> {
    let effects = deferred_turn_authority_effect(
        SessionDeferredTurnAuthorityInput::AllowsInitialTurnOverrides { current_phase },
        "InitialTurnOverridesResolved",
    )?;
    for effect in effects {
        if let SessionDeferredTurnAuthorityEffect::InitialTurnOverridesResolved { allowed } = effect
        {
            return Ok(allowed);
        }
    }
    Err(SessionDeferredTurnAuthorityError {
        op: "InitialTurnOverridesResolved",
    })
}

pub fn stage_initial_prompt(
    state: &mut SessionDeferredTurnState,
    prompt: ContentInput,
    accepted_at: SystemTime,
) -> Result<(), SessionDeferredTurnAuthorityError> {
    let prompt_has_content = prompt.has_images() || !prompt.text_content().trim().is_empty();
    match resolve_initial_prompt_stage(state.first_turn_phase.into(), prompt_has_content)? {
        InitialPromptStageDecision::Store => {
            state.pending_initial_prompt = Some(PendingDeferredPrompt {
                prompt,
                accepted_at,
            });
        }
        InitialPromptStageDecision::Clear => {
            state.pending_initial_prompt = None;
        }
    }
    Ok(())
}

pub fn stage_tool_results(
    state: &mut SessionDeferredTurnState,
    results: Vec<ToolResult>,
    accepted_at: SystemTime,
) -> Result<usize, SessionDeferredTurnAuthorityError> {
    let accepted =
        resolve_tool_results_stage(state.first_turn_phase.into(), usize_to_u64(results.len()))?;
    if accepted == 0 {
        return Ok(0);
    }

    let accepted = usize::try_from(accepted).unwrap_or(usize::MAX);
    state.pending_tool_results.push(PendingToolResultsMessage {
        results,
        accepted_at,
    });
    Ok(accepted)
}

pub fn consume_for_started_turn(
    state: &mut SessionDeferredTurnState,
) -> Result<ConsumedDeferredTurnInputs, SessionDeferredTurnAuthorityError> {
    let restore_first_turn_pending = mark_initial_turn_started(state)?;
    Ok(ConsumedDeferredTurnInputs {
        restore_first_turn_pending,
        pending_initial_prompt: state.pending_initial_prompt.take(),
        pending_tool_results: std::mem::take(&mut state.pending_tool_results),
    })
}

pub fn restore_consumed_turn_inputs(
    state: &mut SessionDeferredTurnState,
    consumed: ConsumedDeferredTurnInputs,
) -> Result<(), SessionDeferredTurnAuthorityError> {
    if consumed.is_empty() {
        return Ok(());
    }
    let (restore_first_turn_pending, restore_initial_prompt, restore_tool_results) =
        resolve_consumed_inputs_restore(
            consumed.restore_first_turn_pending,
            consumed.pending_initial_prompt.is_some(),
            usize_to_u64(consumed.pending_tool_results.len()),
        )?;
    if restore_first_turn_pending {
        restore_initial_turn_pending(state)?;
    }
    if restore_initial_prompt && state.pending_initial_prompt.is_none() {
        state.pending_initial_prompt = consumed.pending_initial_prompt;
    }
    if restore_tool_results {
        let mut restored = consumed.pending_tool_results;
        restored.extend(std::mem::take(&mut state.pending_tool_results));
        state.pending_tool_results = restored;
    }
    Ok(())
}

